package com.trademaster.ims.mobile.reviews.controller;
import com.trademaster.ims.mobile.auth.security.CustomerAuthentication;import com.trademaster.ims.mobile.auth.service.CustomerAuthException;import com.trademaster.ims.mobile.reviews.dto.ReviewDtos.*;import com.trademaster.ims.mobile.reviews.service.CustomerReviewService;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/mobile/v1")public class CustomerReviewController{private final CustomerReviewService s;public CustomerReviewController(CustomerReviewService s){this.s=s;}@GetMapping("/products/{productId}/reviews")List<ReviewResponse>reviews(@PathVariable Long productId){return s.productReviews(productId);}@GetMapping("/products/{productId}/review-summary")ReviewSummaryResponse summary(@PathVariable Long productId){return s.summary(productId);}@GetMapping("/orders/{orderNumber}/reviewable-items")List<ReviewableItemResponse>reviewable(Authentication a,@PathVariable String orderNumber){return s.reviewable(id(a),orderNumber);}@GetMapping("/reviews/my")MyReviewsResponse my(Authentication a){return new MyReviewsResponse(s.my(id(a)));}@PostMapping("/products/{productId}/reviews")@ResponseStatus(HttpStatus.CREATED)ReviewResponse create(Authentication a,@PathVariable Long productId,@Valid @RequestBody ReviewRequest q){return s.create(id(a),productId,q);}@PutMapping("/reviews/{reviewNumber}")ReviewResponse update(Authentication a,@PathVariable String reviewNumber,@Valid @RequestBody ReviewUpdateRequest q){return s.update(id(a),reviewNumber,q);}@PostMapping("/admin/reviews/{reviewNumber}/moderate")@PreAuthorize("hasRole('ADMIN') or hasRole('SUPER_ADMIN')")ReviewResponse moderate(@PathVariable String reviewNumber,@Valid @RequestBody ModerationRequest q){return s.moderate(reviewNumber,q);}private long id(Authentication a){if(a instanceof CustomerAuthentication c)return c.accountId();throw new CustomerAuthException(HttpStatus.UNAUTHORIZED,"AUTHENTICATION_REQUIRED","Authentication is required.");}}